type Speaker = "male" | "female";
type MessageSeed = { speaker: Speaker; text: string; translation: string; highlights: string[] };
type CheckSeed = { question: string; correct: string; wrong: [string, string, string]; explanation: string; skill: string };
type StorySeed = {
  id: string;
  title: string;
  subtitle: string;
  tags: string[];
  maleName: string;
  femaleName: string;
  messages: MessageSeed[];
  checks: CheckSeed[];
  sayingNumbers: [number, number, number, number, number];
};

const level: Level = "upper-intermediate";

function h(phrases: string[]): Highlight[] {
  return phrases.map((phrase) => {
    const saying = colombianSayings.find((item) => item.saying === phrase);
    return { phrase, meaning: saying?.explanation ?? phrase };
  });
}

function buildMessages(storyId: string, seed: StorySeed): StoryMessage[] {
  const chatMessages = seed.messages.map((message, index) => ({
    id: `m${index + 1}`,
    speakerId: message.speaker,
    messageType: (index + 1) % 5 === 0 ? "voice-note" as const : "text" as const,
    text: message.text,
    translation: message.translation,
    audioUrl: (index + 1) % 5 === 0 ? `/audio/stories/${storyId}/m${index + 1}.mp3` : undefined,
    vocabHighlights: h(message.highlights),
  }));

  return [
    {
      id: "n1",
      speakerId: "narrator",
      messageType: "narrator",
      text: `Guía de historia: ${seed.title}. Esta conversación usa cinco dichos colombianos en contexto. Las notas de voz resumen los giros importantes.`,
      translation: `Story guide: ${seed.title}. This conversation uses five Colombian sayings in context. Voice notes summarize the important turns.`,
    },
    ...chatMessages.slice(0, 15),
    {
      id: "n2",
      speakerId: "narrator",
      messageType: "narrator",
      text: "Pausa rápida: identifica qué dicho apareció, quién lo dijo y por qué tenía sentido en la situación.",
      translation: "Quick pause: identify which saying appeared, who said it, and why it made sense in the situation.",
    },
    ...chatMessages.slice(15),
  ];
}

function buildChecks(checkSeeds: CheckSeed[]): StoryComprehensionCheck[] {
  return checkSeeds.map((seed, index) => ({
    id: `check-${index + 1}`,
    afterMessageId: `m${(index + 1) * 3}`,
    question: {
      id: `q-${index + 1}`,
      type: "multiple-choice",
      prompt: seed.question,
      options: [seed.correct, ...seed.wrong],
      correctAnswer: seed.correct,
      explanation: seed.explanation,
      points: 1,
      skillTag: seed.skill,
    } satisfies CheckpointQuestion,
  }));
}

function makeStory(seed: StorySeed): WhatsAppStory {
  const learnedVocab = seed.sayingNumbers.map((number) => colombianSayings[number - 1].saying);

  return {
    id: seed.id,
    title: seed.title,
    subtitle: seed.subtitle,
    languageTarget: "spanish",
    learnerNativeLanguage: "english",
    level,
    tags: ["Colombian Sayings", "text-message-story", ...seed.tags],
    estimatedMinutes: 12,
    skoolSectionName: "Colombian Sayings Stories",
    activityType: "story",
    data: {
      targetLanguage: "spanish",
      nativeLanguage: "english",
      characters: [
        { id: "female", name: seed.femaleName, initials: seed.femaleName[0], side: "right", color: "red" },
        { id: "male", name: seed.maleName, initials: seed.maleName[0], side: "left", color: "blue" },
      ] satisfies StoryCharacter[],
      messages: buildMessages(seed.id, seed),
      comprehensionChecks: buildChecks(seed.checks),
      learnedVocab,
      finalReview: {
        keyPhrases: learnedVocab,
        grammarPatterns: ["Notice how sayings summarize a whole situation.", "Match each saying to the speaker's intention.", "Retell the conflict using one saying naturally."],
        speakingPrompts: ["Explain which saying fits the story best.", "Record a short message using one of the five sayings.", "Say what each character should do next."],
      },
      completionTask: {
        title: "Use one saying",
        instructions: "Record a short Colombian Spanish voice note retelling the story and using one of the five sayings naturally.",
      },
    },
  };
}

